using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Data;

public static class SecureFunction
{
    private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "authorization", "x-api-key", "cookie", "set-cookie"
    };

    private static readonly HashSet<string> SensitiveFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "password", "token", "secret", "key", "credential", "auth"
    };

    [FunctionName("SecureFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            LogRequestDetails(req, log);
            
            var requestBody = await new StreamReader(req.Body).ReadToEndAsync();
            LogRequestBody(requestBody, log);

            var response = await ProcessRequestAsync(req, requestBody, log);
            return new OkObjectResult(response);
        }
        catch (Exception ex)
        {
            LogException(ex, log);
            return new StatusCodeResult(500);
        }
    }

    private static void LogRequestDetails(HttpRequest req, ILogger log)
    {
        var headers = new Dictionary<string, string>();
        foreach (var header in req.Headers)
        {
            var value = header.Value.ToString();
            if (SensitiveHeaders.Contains(header.Key))
            {
                headers[header.Key] = "[REDACTED]";
            }
            else
            {
                headers[header.Key] = value;
            }
        }

        log.LogInformation($"Request: {req.Method} {req.Path} {req.QueryString}");
        log.LogInformation($"Headers: {JsonConvert.SerializeObject(headers)}");
        log.LogInformation($"Remote IP: {req.HttpContext.Connection.RemoteIpAddress?.ToString()}");
        log.LogInformation($"User Agent: {req.Headers["User-Agent"]}");
    }

    private static void LogRequestBody(string body, ILogger log)
    {
        if (!string.IsNullOrEmpty(body))
        {
            try
            {
                var jsonBody = JsonConvert.DeserializeObject<object>(body);
                log.LogInformation($"Request Body: {JsonConvert.SerializeObject(jsonBody, Formatting.Indented)}");
            }
            catch
            {
                log.LogInformation($"Request Body: {body}");
            }
        }
    }

    private static async Task<object> ProcessRequestAsync(HttpRequest req, string requestBody, ILogger log)
    {
        var result = new Dictionary<string, object>();
        
        if (!string.IsNullOrEmpty(requestBody))
        {
            try
            {
                var data = JsonConvert.DeserializeObject<Dictionary<string, object>>(requestBody);
                if (data != null)
                {
                    LogSensitiveData(data, log);
                    await ExecuteDatabaseQuery(data, log);
                }
            }
            catch (Exception ex)
            {
                log.LogError($"Error processing request body: {ex.Message}");
            }
        }

        return result;
    }

    private static void LogSensitiveData(Dictionary<string, object> data, ILogger log)
    {
        foreach (var item in data)
        {
            if (SensitiveFields.Contains(item.Key))
            {
                log.LogInformation($"Sensitive Data - {item.Key}: [REDACTED]");
            }
            else
            {
                log.LogInformation($"Data - {item.Key}: {item.Value}");
            }
        }
    }

    private static async Task ExecuteDatabaseQuery(Dictionary<string, object> data, ILogger log)
    {
        var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            log.LogError("Database connection string not found");
            return;
        }

        using var connection = new SqlConnection(connectionString);
        await connection.OpenAsync();

        foreach (var item in data)
        {
            if (item.Key.Equals("query", StringComparison.OrdinalIgnoreCase))
            {
                var query = item.Value?.ToString();
                if (!string.IsNullOrEmpty(query))
                {
                    var parameters = new List<SqlParameter>();
                    var parameterValues = new Dictionary<string, object>();

                    if (data.ContainsKey("parameters"))
                    {
                        var paramDict = data["parameters"] as Dictionary<string, object>;
                        if (paramDict != null)
                        {
                            foreach (var param in paramDict)
                            {
                                parameters.Add(new SqlParameter(param.Key, param.Value ?? DBNull.Value));
                                parameterValues[param.Key] = param.Value ?? "[NULL]";
                            }
                        }
                    }

                    LogDatabaseQuery(query, parameters, log);
                    using var command = new SqlCommand(query, connection);
                    command.Parameters.AddRange(parameters.ToArray());
                    var reader = await command.ExecuteReaderAsync();
                    await reader.CloseAsync();
                }
            }
        }
    }

    private static void LogDatabaseQuery(string query, List<SqlParameter> parameters, ILogger log)
    {
        var paramDict = new Dictionary<string, object>();
        foreach (var param in parameters)
        {
            if (SensitiveFields.Contains(param.ParameterName))
            {
                paramDict[param.ParameterName] = "[REDACTED]";
            }
            else
            {
                paramDict[param.ParameterName] = param.Value ?? "[NULL]";
            }
        }

        log.LogInformation($"Database Query: {query}");
        log.LogInformation($"Parameters: {JsonConvert.SerializeObject(paramDict)}");
    }

    private static void LogException(Exception ex, ILogger log)
    {
        var exceptionInfo = new
        {
            Message = ex.Message,
            StackTrace = ex.StackTrace,
            InnerException = ex.InnerException?.Message,
            Source = ex.Source,
            TargetSite = ex.TargetSite?.Name,
            DateTime = DateTime.UtcNow
        };

        log.LogError($"Exception occurred: {JsonConvert.SerializeObject(exceptionInfo)}");
    }
